// src/lib/photo-editor/stickers/catalogue.ts
//
// Curated Twemoji catalogue — ~600 emoji across 8 categories.
// Generated by scripts/build-sticker-catalogue.py.
// Each entry holds the lowercase Twemoji codepoint string, a display
// label, and a list of search keywords. Codepoint strings join multi-
// codepoint sequences (flags, ZWJ) with "-" and strip the FE0F
// variation selector — the same convention Twemoji's CDN filenames use.

export type StickerCategoryId =
  | "recents"
  | "smileys"
  | "animals"
  | "food"
  | "travel"
  | "activities"
  | "objects"
  | "symbols"
  | "flags";

export interface StickerCategory {
  id: Exclude<StickerCategoryId, "recents">;
  label: string;
  /** Codepoint of the emoji used as the tab icon. */
  iconCodepoint: string;
  count: number;
}

export interface StickerEntry {
  /** Twemoji codepoint string (e.g. "1f600", "1f1ec-1f1e7"). */
  codepoint: string;
  label: string;
  keywords: readonly string[];
  category: Exclude<StickerCategoryId, "recents">;
}

